import React from "react";

const Services = () => {
  return (
    <section style={{ padding: "40px" }}>
      <h2>Our Services</h2>
      <ul>
        <li>Web Development</li>
        <li>UI Design</li>
        <li>SEO Optimization</li>
      </ul>
    </section>
  );
};

export default Services;
